agent Countdown {
  capability memory.kv("countdown")

  state { }

  enum Phase {
    Ready   -> [Ticking]
    Ticking -> [Done]
    Done    -> []
  }

  on start(n: Int) -> {
    memory.put("remaining", n)
    transition(Phase.Ready)
  }

  on phase(Phase.Ready) -> {
    transition(Phase.Ticking)
  }

  on phase(Phase.Ticking) -> {
    let remaining = memory.get("remaining")!
    transition(Phase.Done)
  }

  on phase(Phase.Done) -> {
    stop()
  }
}
