module Orders {
  enum Status { Pending Paid Shipped Cancelled }

  fn label(s: Status) -> String {
    match s {
      Status.Pending   -> "Pending"
      Status.Paid      -> "Paid"
      Status.Shipped   -> "Shipped"
      Status.Cancelled -> "Cancelled"
    }
  }

  fn is_open(s: Status) -> Bool {
    match s {
      Status.Pending   -> true
      Status.Paid      -> true
      Status.Shipped   -> false
      Status.Cancelled -> false
    }
  }

  test "label covers all variants" {
    assert label(Status.Pending) == "Pending"
    assert label(Status.Paid) == "Paid"
    assert label(Status.Shipped) == "Shipped"
    assert label(Status.Cancelled) == "Cancelled"
  }

  test "is_open true for pending and paid" {
    assert is_open(Status.Pending) == true
    assert is_open(Status.Paid) == true
    assert is_open(Status.Shipped) == false
    assert is_open(Status.Cancelled) == false
  }
}
