module Ping {
  capability http.in

  type EchoBody {
    text: String
  }

  handler http GET "/ping/:name" (req) -> {
    let name = req.params.name
    respond.json(200, { message: "pong ${name}" })
  }

  handler http POST "/echo" (req) -> {
    let body = req.json[EchoBody]()!
    respond.json(200, { echoed: body.text })
  }
