module Scores {
  fn add_bonus(score: Int) -> Int {
    score + 5
  }

  fn is_passing(score: Int) -> Bool {
    score >= 60
  }

  fn curved_passing(scores: List[Int]) -> List[Int] {
    scores
      |> List.map(&add_bonus)
      |> List.filter(&is_passing)
  }

  test "curved_passing applies bonus and keeps passing scores" {
    assert curved_passing([55, 90, 20]) == [60, 95]
  }
}
