module TempMath {
  fn celsius_to_fahrenheit(c: Float) -> Float {
    c * 9.0 / 5.0 + 32.0
  }

  fn clamp(n: Int, low: Int, high: Int) -> Int {
    match n < low {
      true -> low
      false -> match n > high {
        true -> high
        false -> n
      }
    }
  }

  test "celsius_to_fahrenheit converts correctly" {
    assert celsius_to_fahrenheit(0.0) == 32.0
    assert celsius_to_fahrenheit(100.0) == 212.0
  }

  test "clamp bounds values" {
    assert clamp(5, 0, 10) == 5
    assert clamp(-3, 0, 10) == 0
    assert clamp(20, 0, 10) == 10
  }
}
