module Numbers {
  fn parse_and_double(s: String) -> Result[Int, String] {
    let n = Int.parse(s)?
    Ok(n * 2)
  }

  fn sum_or_zero(a: String, b: String) -> Int {
    match Int.parse(a) {
      Ok(x) -> match Int.parse(b) {
        Ok(y)  -> x + y
        Err(_) -> 0
      }
      Err(_) -> 0
    }
  }

  test "parse_and_double success and failure" {
    assert parse_and_double("21") == Ok(42)
    match parse_and_double("nope") {
      Ok(_)  -> assert false
      Err(_) -> assert true
    }
  }

  test "sum_or_zero success and failure" {
    assert sum_or_zero("3", "4") == 7
    assert sum_or_zero("3", "x") == 0
    assert sum_or_zero("y", "4") == 0
  }
}
