module Inventory {
  capability store.table("items", Item)

  type Item {
    sku: String @primary
    qty: Int
  }

  fn restock(sku: String, qty: Int) -> Result[Item, StoreError] {
    let item = { sku: sku, qty: qty }
    store.items.put(item)
  }

  fn lookup_qty(sku: String) -> Int {
    match store.items.get(sku) {
      Ok(item) -> item.qty
      Err(_)   -> 0
    }
  }
}
